COPY public.policy_configs (id, client_config_id, user_id, vulnerability_definition, available_treatments, decision_rules, escalation_rules, created_at, updated_at, affordability_rules, compiled_policy, compiled_at, company_id) FROM stdin;
1	1	ed2fbfa1-28fd-4e0f-8e5a-25240eaec5d1	A customer is vulnerable if there is credible evidence (from customer statements or verified records) of one or more of the following:\nHealth / mental capacity: mental health crisis, suicidal ideation, psychiatric care, serious illness/hospitalization, cognitive impairment/disability affecting communication or decisions, pregnancy/post-partum complications.\nBereavement: customer deceased or death of a close family member.\nSevere accident / safety risk: major injury (customer/dependent), domestic violence/abuse disclosure.\nLegal / exceptional service status: active military deployment/war-zone constraints, incarceration or legal restrictions that materially limit engagement.\nExploitation / loss of control: fraud/scam victim, coerced payments/financial abuse, or concerning third-party control over communication/payments.\n	[{"name": "Forbearance / Payment Holiday", "enabled": true, "definition": "Temporarily pausing or reducing payments for a set period (typically 1-6 months). The loan still accrues interest usually, but the customer gets breathing room. Used when the customer genuinely can't pay right now but the situation is temporary."}, {"name": "Loan Modification / Restructure", "enabled": true, "definition": "Permanently changing the loan terms: extending tenor, reducing interest rate, reducing EMI amount, or some combination. Used when the customer's financial situation has fundamentally changed and the original terms are no longer realistic."}, {"name": "Reaging / Re-amortization", "enabled": true, "definition": "Resetting the delinquency clock back to current after the customer demonstrates good behavior (e.g., 3 consecutive on-time payments). The past-due status is wiped. Sometimes combined with capitalizing the arrears into the remaining loan balance."}, {"name": "Interest Rate Reduction", "enabled": false, "definition": "Specifically lowering the rate, either temporarily or permanently, to make payments more affordable. Sometimes a standalone action, sometimes part of a broader modification."}, {"name": "Capitalization of Arrears", "enabled": false, "definition": "Rolling the missed payment amounts into the remaining principal balance and recalculating the EMI. The customer doesn't have to \\"catch up\\" separately — the arrears just become part of the loan going forward."}, {"name": "Deferment", "enabled": false, "definition": "Specifically for education/student loans, pausing payments entirely because the borrower meets a qualifying condition (still in school, military service, economic hardship). Different from forbearance because it's often interest-free or subsidized."}, {"name": "Clear Arrears Plan", "enabled": true, "definition": "Customer is encouraged to pay above the Minimum Amount Due to clear outstanding arrears within a target period. No loan modification or system intervention needed — the arrears clear naturally through consistent overpayment. Communication includes a specific payment amount and timeline showing month-over-month arrears reduction, plus credit report benefits of becoming current.", "blockedStages": [], "clearanceMonths": 6}]	[{"id": 1, "priority": 1, "willingness": ["ANY"], "affordability": ["HIGH"], "treatmentName": "Clear Arrears Plan", "otherCondition": "(NMPC - MAD) * 6 >= Total Arrears"}, {"id": 2, "priority": 2, "willingness": ["ANY"], "affordability": ["HIGH"], "treatmentName": "Reaging / Re-amortization", "otherCondition": ""}, {"id": 3, "priority": 3, "willingness": ["HIGH", "MEDIUM", "LOW"], "affordability": ["MEDIUM"], "paymentTarget": "At or above MAD", "treatmentName": "None — Encourage Payment", "otherCondition": "", "communicationTone": "Supportive"}, {"id": 4, "priority": 4, "willingness": ["VERY LOW"], "affordability": ["MEDIUM", "LOW", "VERY LOW"], "paymentTarget": "At or above MAD", "treatmentName": "None — Encourage Payment", "otherCondition": "", "communicationTone": "Firm"}, {"id": 5, "priority": 5, "willingness": ["HIGH", "MEDIUM", "LOW"], "affordability": ["LOW"], "treatmentName": "Loan Modification / Restructure", "otherCondition": "", "communicationTone": "Empathetic"}, {"id": 7, "priority": 7, "willingness": ["HIGH", "MEDIUM", "LOW"], "affordability": ["VERY LOW"], "treatmentName": "Forbearance / Payment Holiday", "otherCondition": "", "communicationTone": "Empathetic"}]	{"dpdAbove": null, "brokenPtps": null, "debtDispute": true, "legalAction": true, "balanceAbove": null, "managerRequest": true, "otherConditions": [], "vulnerabilityDetected": true, "otherConditionsLogicOperator": "AND"}	2026-03-05 18:41:47.434643	2026-04-12 08:21:10.388	[{"id": 1, "label": "HIGH", "operator": ">", "condition": "", "isDefault": true, "percentage": 100}, {"id": 2, "label": "MEDIUM", "operator": ">=", "condition": "and < Minimum Amount Due", "isDefault": true, "percentage": 60}, {"id": 3, "label": "LOW", "operator": "<", "condition": "", "isDefault": true, "percentage": 60}, {"id": 4, "label": "VERY LOW", "operator": "<", "condition": "NMPC = 0 OR NMPC < 10% of Minimum Amount Due", "isDefault": true, "percentage": 10}, {"id": 5, "label": "NOT SURE", "operator": "=", "condition": "Not enough data to estimate NMPC or Minimum Amount Due not provided", "isDefault": true, "percentage": null}]	{"dpdStages": "DPD Stage Definitions:\\n- Pre Due: -5 to 0 DPD\\n- Grace: 1 to 3 DPD\\n- Early: 1 to 30 DPD\\n- Mid: 31 to 90 DPD\\n- Late: 91 to 180 DPD\\n", "escalation": "ESCALATION RULES - always route to human when:\\n- Vulnerability detected (LOCKED - always active)\\n- Customer mentions legal action\\n- Customer disputes the debt\\n- Customer requests to speak to manager\\n", "contactRules": "CONTACT RULES:\\n- Check last outreach before proposing new contact.\\n- Respect cooldown periods between outreach attempts.\\n- Prioritize the channel most likely to get a response based on history.\\n", "cooldownDays": "7", "lookbackDays": "180", "affordability": "AFFORDABILITY LABEL RULES:\\n- HIGH: estimated monthly payment capacity > 100% of minimum amount due\\n- MEDIUM: estimated monthly payment capacity >= 60% of minimum amount due (and < Minimum Amount Due)\\n- LOW: estimated monthly payment capacity < 60% of minimum amount due\\n- VERY LOW: estimated monthly payment capacity < 10% of minimum amount due (NMPC = 0 OR NMPC < 10% of Minimum Amount Due)\\n- NOT SURE: Not enough data to estimate NMPC or Minimum Amount Due not provided\\n", "decisionRules": "DECISION RULES (evaluate in order, first match wins):\\n\\nRule 1: IF (NMPC - MAD) * 6 >= Total Arrears AND affordability = HIGH\\n  THEN recommend: Clear Arrears Plan\\n  COMMUNICATION TONE: Supportive\\n  Tone guidelines:\\n  - Encourage payment, highlight credit health benefits,\\n    explain how staying current protects their financial\\n    future. Be warm and motivating.\\n\\nRule 2: IF affordability = HIGH\\n  THEN recommend: Reaging / Re-amortization\\n  COMMUNICATION TONE: Supportive\\n  Tone guidelines:\\n  - Encourage payment, highlight credit health benefits,\\n    explain how staying current protects their financial\\n    future. Be warm and motivating.\\n\\nRule 3: IF affordability = MEDIUM AND willingness IN [HIGH, MEDIUM, LOW]\\n  THEN: No loan treatment required — encourage payment.\\n  PAYMENT TARGET: At or above minimum amount due\\n  EMAIL RULE: The proposed email MUST encourage the customer to pay at least the minimum amount due (MAD). Do NOT suggest that paying below the minimum amount is acceptable or a positive step. Frame the minimum amount as the baseline expectation.\\n  COMMUNICATION TONE: Supportive\\n  Tone guidelines:\\n  - Encourage payment, highlight credit health benefits,\\n    explain how staying current protects their financial\\n    future. Be warm and motivating.\\n\\nRule 4: IF affordability IN [MEDIUM, LOW, VERY LOW] AND willingness = VERY LOW\\n  THEN: No loan treatment required — encourage payment.\\n  PAYMENT TARGET: At or above minimum amount due\\n  EMAIL RULE: The proposed email MUST encourage the customer to pay at least the minimum amount due (MAD). Do NOT suggest that paying below the minimum amount is acceptable or a positive step. Frame the minimum amount as the baseline expectation.\\n  COMMUNICATION TONE: Firm\\n  Tone guidelines:\\n  - Be direct and professional. State that they need to\\n    engage with us so we can help. Explain that continued\\n    non-payment will damage their credit report and have\\n    long-term consequences. Still offer help but create urgency.\\n\\nRule 5: IF affordability = LOW AND willingness IN [HIGH, MEDIUM, LOW]\\n  THEN recommend: Loan Modification / Restructure\\n  COMMUNICATION TONE: Empathetic\\n  Tone guidelines:\\n  - Acknowledge their situation, express willingness to find\\n    solutions together, reassure them that engaging with us\\n    is the first step.\\n\\nRule 7: IF affordability = VERY LOW AND willingness IN [HIGH, MEDIUM, LOW]\\n  THEN recommend: Forbearance / Payment Holiday\\n  COMMUNICATION TONE: Empathetic\\n  Tone guidelines:\\n  - Acknowledge their situation, express willingness to find\\n    solutions together, reassure them that engaging with us\\n    is the first step.\\n\\nDEFAULT: If no rule matches, recommend Agent Review (insufficient data).\\n", "vulnerability": "VULNERABILITY POLICY:\\nA customer is vulnerable if:\\nA customer is vulnerable if there is credible evidence (from customer statements or verified records) of one or more of the following:\\nHealth / mental capacity: mental health crisis, suicidal ideation, psychiatric care, serious illness/hospitalization, cognitive impairment/disability affecting communication or decisions, pregnancy/post-partum complications.\\nBereavement: customer deceased or death of a close family member.\\nSevere accident / safety risk: major injury (customer/dependent), domestic violence/abuse disclosure.\\nLegal / exceptional service status: active military deployment/war-zone constraints, incarceration or legal restrictions that materially limit engagement.\\nExploitation / loss of control: fraud/scam victim, coerced payments/financial abuse, or concerning third-party control over communication/payments.\\n\\nIf vulnerability = TRUE, Beacon MUST recommend Agent Review.", "treatmentCatalog": "AVAILABLE TREATMENTS:\\n- Forbearance / Payment Holiday: ALLOWED in [Pre Due, Grace, Early, Mid, Late]\\n  Definition: Temporarily pausing or reducing payments for a set period (typically 1-6 months). The loan still accrues interest usually, but the customer gets breathing room. Used when the customer genuinely can't pay right now but the situation is temporary.\\n- Loan Modification / Restructure: ALLOWED in [Pre Due, Grace, Early, Mid, Late]\\n  Definition: Permanently changing the loan terms: extending tenor, reducing interest rate, reducing EMI amount, or some combination. Used when the customer's financial situation has fundamentally changed and the original terms are no longer realistic.\\n- Reaging / Re-amortization: ALLOWED in [Pre Due, Grace, Early, Mid, Late]\\n  Definition: Resetting the delinquency clock back to current after the customer demonstrates good behavior (e.g., 3 consecutive on-time payments). The past-due status is wiped. Sometimes combined with capitalizing the arrears into the remaining loan balance.\\n\\nTREATMENT: Clear Arrears Plan\\nAvailable in: [Pre Due, Grace, Early, Mid, Late]\\nDefinition: Customer pays above minimum amount due to clear arrears within target window.\\nEligibility condition: (estimated monthly payment capacity - minimum amount due) * 6 >= Total Arrears\\n  where 6 = configured maximum months (client-configurable)\\n\\nWhen recommending Clear Arrears Plan, you MUST calculate and include:\\n  1. Monthly payment needed = minimum amount due + (Total Arrears / 6)\\n  2. Actual months to clear = ceiling(Total Arrears / (estimated monthly payment capacity - minimum amount due))\\n  3. Month-by-month projection showing arrears balance reducing to zero\\n\\nIf (estimated monthly payment capacity - minimum amount due) * 6 < Total Arrears, this treatment\\ndoes NOT qualify. Skip to next matching decision rule.\\n", "treatmentBlocklist": "TREATMENT BLOCKLIST:\\n\\nGLOBALLY DISABLED (never recommend):\\n- Interest Rate Reduction\\n- Capitalization of Arrears\\n- Deferment\\n"}	2026-04-12 08:21:10.388	88bb298f-0fd9-407b-ad75-1ed7ae2ac794
2	\N	0fca104f-a7aa-4aa1-99b6-0ebf95f6d2b4		[{"name": "Forbearance / Payment Holiday", "enabled": false, "definition": "Temporarily pausing or reducing payments for a set period (typically 1-6 months). The loan still accrues interest usually, but the customer gets breathing room. Used when the customer genuinely can't pay right now but the situation is temporary."}, {"name": "Loan Modification / Restructure", "enabled": false, "definition": "Permanently changing the loan terms: extending tenor, reducing interest rate, reducing EMI amount, or some combination. Used when the customer's financial situation has fundamentally changed and the original terms are no longer realistic."}, {"name": "Reaging / Re-amortization", "enabled": false, "definition": "Resetting the delinquency clock back to current after the customer demonstrates good behavior (e.g., 3 consecutive on-time payments). The past-due status is wiped. Sometimes combined with capitalizing the arrears into the remaining loan balance."}, {"name": "Interest Rate Reduction", "enabled": false, "definition": "Specifically lowering the rate, either temporarily or permanently, to make payments more affordable. Sometimes a standalone action, sometimes part of a broader modification."}, {"name": "Capitalization of Arrears", "enabled": false, "definition": "Rolling the missed payment amounts into the remaining principal balance and recalculating the EMI. The customer doesn't have to \\"catch up\\" separately — the arrears just become part of the loan going forward."}, {"name": "Deferment", "enabled": false, "definition": "Specifically for education/student loans, pausing payments entirely because the borrower meets a qualifying condition (still in school, military service, economic hardship). Different from forbearance because it's often interest-free or subsidized."}, {"name": "Clear Arrears Plan", "enabled": false, "definition": "Customer is encouraged to pay above the Minimum Amount Due to clear outstanding arrears within a target period. No loan modification or system intervention needed — the arrears clear naturally through consistent overpayment. Communication includes a specific payment amount and timeline showing month-over-month arrears reduction, plus credit report benefits of becoming current.", "blockedStages": ["Late"], "clearanceMonths": 6}]	[]	{"dpdAbove": null, "brokenPtps": null, "debtDispute": false, "legalAction": false, "balanceAbove": null, "managerRequest": false, "otherConditions": [], "vulnerabilityDetected": true, "otherConditionsLogicOperator": "AND"}	2026-04-11 06:34:53.618889	2026-04-11 14:21:39.407	[]	{"dpdStages": "DPD Stage Definitions:\\n- No stages configured\\n", "escalation": "ESCALATION RULES - always route to human when:\\n- Vulnerability detected (LOCKED - always active)\\n", "contactRules": "CONTACT RULES:\\n- Check last outreach before proposing new contact.\\n- Respect cooldown periods between outreach attempts.\\n- Prioritize the channel most likely to get a response based on history.\\n", "cooldownDays": "7", "lookbackDays": "180", "affordability": "AFFORDABILITY LABEL RULES:\\n- HIGH: estimated monthly payment capacity >= 100% of minimum amount due\\n- MEDIUM: estimated monthly payment capacity >= 60% and < 100% of minimum amount due\\n- LOW: estimated monthly payment capacity >= 10% and < 60% of minimum amount due\\n- VERY LOW: estimated monthly payment capacity = 0 OR < 10% of minimum amount due\\n- NOT SURE: Absolutely no payment data, no conversation data, and no income data exists to estimate capacity", "decisionRules": "DECISION RULES (evaluate in order, first match wins):\\n- No rules configured. Use Agent Review as default.\\n\\nDEFAULT: If no rule matches, recommend Agent Review (insufficient data).\\n", "vulnerability": "", "treatmentCatalog": "AVAILABLE TREATMENTS:\\n", "treatmentBlocklist": "TREATMENT BLOCKLIST:\\n\\nGLOBALLY DISABLED (never recommend):\\n- Forbearance / Payment Holiday\\n- Loan Modification / Restructure\\n- Reaging / Re-amortization\\n- Interest Rate Reduction\\n- Capitalization of Arrears\\n- Deferment\\n- Clear Arrears Plan\\n"}	2026-04-11 14:21:39.407	f8e55a8d-ff5b-4fc5-9e1f-f5ef1564e309
