cial Difficulty", "defaultValue": "false", "allowedValues": [], "businessMeaning": "A trigger for forbearance assessment and an input for Payment Deferral eligibility (SOP 4.3)."}, {"dataType": "string", "fieldName": "deferral_reason", "description": "The reason provided by the customer for needing a payment deferral.", "displayName": "Deferral Reason", "defaultValue": "", "allowedValues": [], "businessMeaning": "A required field for documenting the circumstances leading to a Payment Deferral, as per SOP 4.3."}, {"dataType": "boolean", "fieldName": "consent_for_mandate_reactivation", "description": "Indicates whether the customer has consented to their payment mandate being reactivated after the deferral period ends.", "displayName": "Consent for Mandate Reactivation", "defaultValue": "false", "allowedValues": [], "businessMeaning": "A required consent to be captured before applying a Payment Deferral, as per SOP 4.3."}]	high
